import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const h=JSON.parse('{"title":"Custom Markers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/custom-markers.md","filePath":"guide/custom-markers.md","lastUpdated":1773300184000}'),n={name:"guide/custom-markers.md"};function s(i,e,l,c,m,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="custom-markers" tabindex="-1">Custom Markers <a class="header-anchor" href="#custom-markers" aria-label="Permalink to &quot;Custom Markers&quot;">​</a></h1><p>getbased has a built-in schema of 287+ biomarkers across 16 categories. When you import a PDF that contains a result the app doesn&#39;t recognize — a specialty marker, a newer test, or one with an unusual name — it&#39;s automatically created as a <strong>custom marker</strong> rather than being discarded.</p><h2 id="creating-custom-markers-manually" tabindex="-1">Creating Custom Markers Manually <a class="header-anchor" href="#creating-custom-markers-manually" aria-label="Permalink to &quot;Creating Custom Markers Manually&quot;">​</a></h2><p>You can create a new biomarker without importing a PDF:</p><ol><li>In the sidebar, click the <strong>+</strong> button next to &quot;Categories&quot;</li><li>Choose an existing <strong>category</strong> or create a new one</li><li>Enter the <strong>marker name</strong>, <strong>unit</strong>, and optionally a <strong>reference range</strong> and <strong>optimal range</strong></li><li>Click <strong>Create</strong> — the app immediately opens the Add Value form so you can enter your first data point</li></ol><p>This is useful when you have results from a lab the AI doesn&#39;t fully support, or you want to track something not in the standard schema (e.g., deuterium levels, specialist tests, home monitoring devices).</p><p>Custom markers you create manually are included in the AI&#39;s marker reference list, so if you later import a PDF containing that marker, the AI will map it automatically.</p><h2 id="how-custom-markers-are-created-during-import" tabindex="-1">How Custom Markers Are Created During Import <a class="header-anchor" href="#how-custom-markers-are-created-during-import" aria-label="Permalink to &quot;How Custom Markers Are Created During Import&quot;">​</a></h2><p>During PDF import, the AI identifies any results that don&#39;t match a known marker. For each unrecognized result, the AI suggests:</p><ul><li>A <strong>category</strong> to place it in (e.g., biochemistry, hormones)</li><li>A <strong>name</strong> for the marker (in plain English)</li><li>The <strong>unit</strong> it&#39;s measured in</li><li>A <strong>reference range</strong> (minimum and maximum) based on the lab report or medical knowledge</li></ul><p>These suggestions appear in the import preview with a <strong>blue &quot;New&quot;</strong> badge. You can review them before confirming.</p><h2 id="where-custom-markers-appear" tabindex="-1">Where Custom Markers Appear <a class="header-anchor" href="#where-custom-markers-appear" aria-label="Permalink to &quot;Where Custom Markers Appear&quot;">​</a></h2><p>Once created, custom markers are treated the same as built-in markers throughout the app:</p><ul><li>They appear in <strong>charts</strong> with reference range bands and trend detection</li><li>They show up in <strong>data tables</strong> and the marker <strong>glossary</strong></li><li>They&#39;re included in <strong>AI chat context</strong>, so the assistant knows about them when you ask questions</li><li>They&#39;re exported in your <strong>JSON backup</strong> and restored on import</li><li>They&#39;re included when you import future PDFs — the AI uses them to avoid creating duplicates</li></ul><h2 id="category-assignment" tabindex="-1">Category Assignment <a class="header-anchor" href="#category-assignment" aria-label="Permalink to &quot;Category Assignment&quot;">​</a></h2><p>If a custom marker belongs to a category that doesn&#39;t exist yet in the built-in schema, a new category is created automatically with an auto-inferred icon (or a bookmark icon as fallback). It appears in the sidebar alongside the standard categories.</p><h3 id="renaming-categories" tabindex="-1">Renaming Categories <a class="header-anchor" href="#renaming-categories" aria-label="Permalink to &quot;Renaming Categories&quot;">​</a></h3><p>Click the category name in the category view header to rename it. The new label is saved as a display override — the underlying key is unchanged, so existing data and exports are unaffected.</p><h3 id="changing-category-icons" tabindex="-1">Changing Category Icons <a class="header-anchor" href="#changing-category-icons" aria-label="Permalink to &quot;Changing Category Icons&quot;">​</a></h3><p>Click the icon next to any category name to open the <strong>emoji picker</strong>. The picker has categorized emoji tabs (Science, Health, Nature, Food, Objects), a search field, and a <strong>Reset</strong> button to revert to the default icon. You can also pick an icon when creating a new category via the &quot;+&quot; sidebar button.</p><h2 id="specialty-lab-pipeline" tabindex="-1">Specialty Lab Pipeline <a class="header-anchor" href="#specialty-lab-pipeline" aria-label="Permalink to &quot;Specialty Lab Pipeline&quot;">​</a></h2><p>For non-blood tests (OAT, DUTCH, HTMA, etc.), custom markers are created with a <strong>group</strong> field that determines their sidebar placement. The AI assigns test-type-prefixed categories (e.g., <code>oatNutritional</code>, <code>dutchHormones</code>) and groups them under collapsible sidebar headers.</p><p>This means an OAT import creates categories like &quot;Nutritional Markers&quot; and &quot;Microbial Overgrowth&quot; — all organized under an <strong>OAT</strong> header in the sidebar. See <a href="./specialty-labs.html">Specialty Labs</a> for the full details.</p><h2 id="editing-custom-markers" tabindex="-1">Editing Custom Markers <a class="header-anchor" href="#editing-custom-markers" aria-label="Permalink to &quot;Editing Custom Markers&quot;">​</a></h2><p>Custom marker definitions (name, unit, reference range) are set when first created and won&#39;t be overwritten by future imports of the same marker. Reference and optimal ranges can be edited by clicking the range values in the marker&#39;s detail modal. If a custom marker has no ranges set, a clickable &quot;Reference: – – –&quot; placeholder appears — click it to add ranges.</p><p>You can create open-ended ranges by clearing one side using the × button next to the input field. For example, setting only a lower bound of 59 creates a &quot;&gt;59&quot; range.</p><h2 id="deleting-custom-markers" tabindex="-1">Deleting Custom Markers <a class="header-anchor" href="#deleting-custom-markers" aria-label="Permalink to &quot;Deleting Custom Markers&quot;">​</a></h2><p>To delete a custom marker and all its values, open the marker&#39;s detail modal and click <strong>Delete this marker</strong> at the bottom. If it&#39;s the last marker in its category, the entire category is removed. This cannot be undone.</p><div class="tip custom-block"><p class="custom-block-title">Niche and specialty markers</p><p>Custom markers work well for less common tests like omega-3 index, micronutrients, organic acids, or functional medicine panels that aren&#39;t in the standard schema. Import the PDF and the AI handles the mapping automatically.</p></div><div class="tip custom-block"><p class="custom-block-title">Duplicate prevention</p><p>The AI is aware of all existing custom markers when processing new PDFs. It won&#39;t create a second definition for a marker that already exists, even if the name appears slightly differently across different lab reports.</p></div>',30)])])}const g=a(n,[["render",s]]);export{h as __pageData,g as default};
